import React, { useState, useEffect } from 'react';
import ProductCard from './ProductCard';
import { API_ENDPOINTS } from '../config/api';

const ProductGrid = ({ filters, setFilters }) => {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchProducts();
  }, [filters]);

  const fetchProducts = async () => {
    setLoading(true);
    try {
      let url = API_ENDPOINTS.PRODUCTS;
      const params = new URLSearchParams();

      if (filters.brands.length > 0) {
        params.append('brand', filters.brands.join(','));
      }
      if (filters.minPrice) {
        params.append('minPrice', filters.minPrice);
      }
      if (filters.maxPrice) {
        params.append('maxPrice', filters.maxPrice);
      }
      if (filters.keyword) {
        params.append('keyword', filters.keyword);
      }

      if (params.toString()) {
        url += '?' + params.toString();
      }

      const response = await fetch(url);
      const data = await response.json();

      let result = data.records || [];

      if (filters.sort === 'price-asc') {
        result.sort((a, b) => parseFloat(a.price) - parseFloat(b.price));
      } else if (filters.sort === 'price-desc') {
        result.sort((a, b) => parseFloat(b.price) - parseFloat(a.price));
      }

      setProducts(result);
    } catch (error) {
      console.error('Error fetching products:', error);
      setProducts([]);
    } finally {
      setLoading(false);
    }
  };
  const sortOptions = [
    { value: 'newest', label: 'Mới nhất' },
    { value: 'bestseller', label: 'Bán chạy' },
    { value: 'price-asc', label: 'Giá thấp - cao' },
    { value: 'price-desc', label: 'Giá cao - thấp' }
  ];

  if (loading) {
    return (
      <section className="flex-1 flex items-center justify-center h-96">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary mx-auto mb-4"></div>
          <p className="text-slate-500">Đang tải sản phẩm...</p>
        </div>
      </section>
    );
  }

  return (
    <section className="flex-1">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-6 bg-white dark:bg-background-dark p-4 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm">
        <p className="text-sm"><span className="font-bold text-primary">{products.length}</span> sản phẩm được tìm thấy</p>
        <div className="flex items-center gap-2 overflow-x-auto">
          <span className="text-sm text-slate-500 whitespace-nowrap">Sắp xếp:</span>
          {sortOptions.map((sort) => (
            <button 
              key={sort.value} 
              onClick={() => setFilters({ ...filters, sort: sort.value })}
              className={`px-3 py-1.5 text-xs ${filters.sort === sort.value ? 'bg-primary text-white' : 'bg-slate-100 dark:bg-slate-800'} rounded-lg whitespace-nowrap`}
            >
              {sort.label}
            </button>
          ))}
        </div>
      </div>
      <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-4">
        {products.length > 0 ? (
          products.map(product => (
            <ProductCard 
              key={product.id} 
              product={{
                ...product,
                price: new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(product.price),
                oldPrice: product.original_price ? new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(product.original_price) : null,
                badge: product.discount ? `-${product.discount}%` : null,
                specs: [product.cpu, product.ram, product.storage].filter(Boolean)
              }} 
            />
          ))
        ) : (
          <div className="col-span-full text-center py-12">
            <p className="text-slate-500">Không tìm thấy sản phẩm nào</p>
          </div>
        )}
      </div>
      <div className="flex justify-center mt-12 mb-8 gap-2">
        <button className="w-10 h-10 flex items-center justify-center rounded-lg border border-slate-200 hover:border-primary hover:text-primary transition-all">
          <span className="material-symbols-outlined">chevron_left</span>
        </button>
        <button className="w-10 h-10 flex items-center justify-center rounded-lg bg-primary text-white font-bold">1</button>
        <button className="w-10 h-10 flex items-center justify-center rounded-lg border border-slate-200 hover:border-primary hover:text-primary transition-all">2</button>
        <button className="w-10 h-10 flex items-center justify-center rounded-lg border border-slate-200 hover:border-primary hover:text-primary transition-all">3</button>
        <button className="w-10 h-10 flex items-center justify-center rounded-lg border border-slate-200 hover:border-primary hover:text-primary transition-all">
          <span className="material-symbols-outlined">chevron_right</span>
        </button>
      </div>
    </section>
  );
};

export default ProductGrid;
